function extractEmail(from) {
  if (!from) return '';
  if (typeof from === 'object' && Array.isArray(from.value)) {
    return from.value[0]?.address || '';
  }
  if (Array.isArray(from)) {
    return from[0]?.address || '';
  }
  if (typeof from === 'string') {
    const match = from.match(/<([^>]+)>/);
    return match ? match[1].trim() : from.trim();
  }
  return '';
}

const email = $input.first().json;
const sender  = extractEmail(email.from);
const subject = email.subject || '';
const body    = email.text || email.html || '';
const messageId = email.id || email.messageId || '';
const text = (subject + ' ' + body).toLowerCase();

const roomKeywords  = ['room','conference','meeting room','boardroom','board room','auditorium','hall','venue','book a room','reserve a room','reservation'];
const assetKeywords = ['laptop','computer','monitor','keyboard','mouse','tablet','ipad','phone','camera','projector','equipment','device','charger','cable','headset','borrow','rent','check out','asset','locker','desk','hot desk','parking','vehicle','car','van'];
const aiKeywords    = ['urgent','critical','asap','immediately','emergency','approval','approve','budget','permission','access','request','authorize','grant','deny','escalate','important','deadline','compliance','policy','exception','override','it support','software'];

const needsRoom  = roomKeywords.some(k => text.includes(k));
const needsAsset = assetKeywords.some(k => text.includes(k));
const needsAI    = aiKeywords.some(k => text.includes(k));

let route;
if (needsRoom)       route = 'room';
else if (needsAsset) route = 'asset';
else if (needsAI)    route = 'ai_only';
else                 route = 'simple';

return [{ json: { sender, subject, body, message_id: messageId, route, gmail_id: messageId } }];

